from haystack import Pipeline
from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever

class DriftMonitor:
    def __init__(self):
        self.baseline_score = None
        self.score_history = []

    def monitor_retriever(self, retriever, query):
        result = retriever.run(query=query)
        docs = result.get('documents', [])
        if docs:
            avg_score = sum(doc.score or 0 for doc in docs) / len(docs)
            self.score_history.append(avg_score)

            if self.baseline_score is None:
                self.baseline_score = avg_score
            elif avg_score < self.baseline_score * 0.85:
                print(f'🚨 RETRIEVER DRIFT: {avg_score:.3f} vs baseline {self.baseline_score:.3f}')
        return result

from typing import List, Union
from haystack.dataclasses import Document

class TypeChecker:
    def __init__(self):
        self.type_contracts = {
            'retriever': List[Document],
            'generator': str,
            'reranker': List[Document]
        }

    def validate_output(self, component_name: str, output: any) -> bool:
        expected_type = self.type_contracts.get(component_name)

        if expected_type == List[Document]:
            if not isinstance(output, list) or not all(isinstance(d, Document) for d in output):
                print(f'🚨 TYPE MISMATCH: {component_name} expected List[Document], got {type(output)}')
                return False
        elif expected_type == str and not isinstance(output, str):
            print(f'🚨 TYPE MISMATCH: {component_name} expected str, got {type(output)}')
            return False

        return True

