from haystack.components.generators import OpenAIGenerator

class GroundedGenerator(OpenAIGenerator):
    def __init__(self, **kwargs):
        prompt_template = """
        Context: {{context}}

        Answer the question using ONLY the context above. If the answer isn't in the context, say 'I don't know'. Do not make up answers.

        Question: {{query}}
        Answer:"""
        super().__init__(prompt_template=prompt_template, **kwargs)

from haystack import component

@component
class SafeReranker:
    @component.output_types(documents=list[Document])
    def run(self, documents: list[Document]) -> dict:
        if not documents:
            raise ValueError('Reranker received empty document list')

        try:
            # Reranking logic here
            reranked_docs = self._rerank(documents)
            if not reranked_docs:
                raise ValueError('Reranker produced no valid outputs')
            return {'documents': reranked_docs}
        except Exception as e:
            raise RuntimeError(f'Reranker failed: {str(e)}') from e
